import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./resetpassword.css";

const ResetPassword = () => {
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const navigate = useNavigate();

  const handleResetPassword = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (!password || !confirmPassword) {
      setError("Both fields are required.");
      return;
    }
    
    if (password !== confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/;
    if (!passwordRegex.test(password)) {
      setError("Password must be at least 8 characters, include uppercase, lowercase, a number, and a special character.");
      return;
    }

    try {
      setIsSubmitting(true);
      const email = localStorage.getItem("resetEmail");
      const otpToken = localStorage.getItem("otpToken");

      if (!email || !otpToken) {
        setError("Session expired. Please request a new OTP.");
        return;
      }

      const response = await axios.post("http://localhost:5000/api/auth/reset-password", {
        email,
        password,
        otpToken,
      });

      if (response.data.success) {
        setMessage("Password reset successfully! Redirecting to login...");
        localStorage.removeItem("resetEmail");
        localStorage.removeItem("otpToken");
        setTimeout(() => navigate("/login"), 2000);
      } else {
        setError(response.data.message || "Failed to reset password.");
      }
    } catch (err) {
      setError("Error resetting password. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="reset-password-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />
      <div className="reset-password-card">
        <h2>Reset Password</h2>
        <form onSubmit={handleResetPassword}>
          <input
            type="password"
            placeholder="Enter new password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            disabled={isSubmitting}
          />
          <input
            type="password"
            placeholder="Confirm new password"
            value={confirmPassword}
            onChange={(e) => setConfirmPassword(e.target.value)}
            required
            disabled={isSubmitting}
          />
          <button type="submit" className="reset-password-button" disabled={isSubmitting}>
            {isSubmitting ? "Resetting..." : "Reset Password"}
          </button>
          {message && <p className="success-message">{message}</p>}
          {error && <p className="error-message">{error}</p>}
        </form>
      </div>
      <button onClick={() => navigate("/login")} className="back-button">Back to Login</button>
    </div>
  );
};

export default ResetPassword;
